namespace MUD_MetroHra;class Program{    static async Task Main(string[] args)    {        int port = 5000;        if (args.Length > 0 && int.TryParse(args[0], out var parsedPort))            port = parsedPort;        var world = WorldLoader.Load("world.json");        var accountService = new AccountService();        var persistenceService = new PersistenceService();        var server = new GameServer(port, world, accountService, persistenceService);        await server.StartAsync();    }}